+	if err != nil {
+		return nil, err
+	}
+	origin := ""
+	var urls []string
+	for _, line := range strings.Split(strings.TrimSpace(out), "\n") {
+		fields := strings.Fields(line)
+		if len(fields) < 2 {
+			continue
+		}
+		key := fields[0]
+		url := fields[1]
+		if key == "remote.origin.url" {
+			origin = url
+			continue
+		}
+		urls = append(urls, url)
+	}
+	if origin != "" {
+		urls = append([]string{origin}, urls...)
+	}
+	return urls, nil
+}
